module SIPO_Switch (  
    input clk,  
    input reset,  
    input serial_in,  
    output reg [4:0] parallel_out  
);  
    reg [4:0] flip_flop;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            flip_flop <= 5'b00000;  
        end else begin  
            flip_flop <= {flip_flop[3:0], serial_in};  
        end  
    end  

    always @(*) begin  
        parallel_out = flip_flop;  
    end  
endmodule
